INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00727', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄暴行的相關理論解釋，下列敘述何者正確？', '["受刑人平衡理論主張，監獄暴行的發生，起因於公權力無法彰顯", "輸入模式理論認為監獄暴行的發生，係受刑人從本身的經驗及認知的影響，入獄前即有暴力傾 向是暴行的預測因子", "行政管理理論認為監獄暴行的發生，是監獄管理當局破壞了監獄內非正式的社會控制所造成的 結果", "剝奪模式理論主張監獄暴行的發生，是受刑人個人認知及動機上的延伸，為其入監前行為類型 的反應，並非完全對監禁的反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00728', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於戒護勤務崗位之值勤要領的敘述，下列何者正確？', '["出入車輛之檢查，因設有「複檢站」複檢機制，所以主出入口「車檢站」值勤員只要負責登記 放行即可，不必檢查，以節省時間", "戒護外醫勤務，出發前應通知受刑人家屬，以利家屬前往醫院門診協助掛號事宜", "舍房夜間勤務著重人數查察、受刑人打架違規行為之阻止，故巡房時遇受刑人身體反映病痛， 只要記錄供隔日衛生科處置即可，不必通報中央台（勤務中心）", "戒護人員值炊場勤務時，應注意主副食品應由收容人輪流推舉的代表（監廚）司秤，眼同下鍋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00729', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '學者赫佛蘭（Heffernan,1972）在研究維吉尼亞州哥倫比亞女子監獄時，發現女性受刑人有三種適 應角色，下列敘述何者錯誤？', '["打混型（DoingTime）", "老實型／保守型（TheSquare）", "習慣性犯罪者／固執型（TheLife）", "職業犯罪者／過客型（TheCool）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00730', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列何者與監獄暴行最不具關聯性？', '["監獄擁擠", "受刑人刑期", "犯罪類型", "入監前職業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00731', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關矯正機關戒護事故之定義與意涵，下列敘述何者錯誤？', '["「戒護」一詞，即警戒（Surveillance）、保護（Protection）之意思", "戒護事故僅指脫逃及暴行之行為", "「戒護事故」，係指監獄內發生異於常態、暫時性失去控制與掌握的突發事故", "戒護事故發生原因當然有共同的、個別的、預謀的及突發的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00732', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列何者不是監獄發生暴動之主要原因？', '["對收容人違規行為之處置時機與方式不當或懲罰不公，造成收容人不服監獄管理", "行刑處遇及生活待遇不適當引起不滿與怨懟心理，壓抑持久", "收容人攜帶菸品及檳榔違禁品入監", "平時收容人申訴意見未能妥適處理或主動溝通，下情無法上達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00733', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關我國監獄脫逃事故原因與相關防範對策之敘述，下列何者錯誤？', '["應特別注意高齡受刑人之生活情狀，以防範其脫逃", "尚有他案審理中，結果將對其不利，心生畏懼，是收容人脫逃原因之一", "脫逃之方式有利用出庭、借提、移監之機會脫逃等", "不使收容人脫離戒護視線，是防止脫逃方式之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00734', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄受刑人間發生性侵害行為之原因與預防對策的敘述，下列何者錯誤？', '["自我控制力強之受刑人，會以正確的方式來轉移對性的需求，惟自我控制力弱，又再結合暴力、 攻擊行為之受刑人，則性侵害事件即有可能發生", "大部分監獄內性侵害行為的發生均為勸誘的影響，例如使用說服、賄賂、詐欺、情感或物質的 引誘所致", "監獄應落實調查分類，針對具性觀念與性行為偏差、具暴力、攻擊行為之受刑人、或有性侵害 行為前科者嚴加分類，以減少此類事件的發生", "管教人員應正視性侵害行為的發生，不可消極或視而不見，應正確教導灌輸受刑人正確性知識 與觀念"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00735', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '109年7月15日修正施行之監獄行刑法，為保障矯正人權而增訂部分條文，下列敘述何者非增訂部 分？', '["增訂監獄人員執行國家之刑罰權，應尊重受刑人尊嚴及維護其人權", "增訂監獄應設獨立之外部視察小組，落實矯正機關透明化、公開化", "增訂累進處遇之相關規定，鼓勵受刑人保持善行", "增訂陳情、申訴及起訴相關規定，保障受刑人相關救濟權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00736', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑與受刑人社會化之關聯性，下列敘述何者錯誤？', '["監獄藉由隔離監禁及教化來排除受刑人之反社會性", "以應報及威嚇手段重建受刑人之社會化", "監獄行刑矯治處遇目的之一為培養其適應社會生活之能力", "監獄行刑具積極教育、矯治作用，促使受刑人再社會化之功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
